/**
 * Core notification types and interfaces.
 *
 * These types define the notification domain model used throughout the system.
 * All notification channels (email, webhook, in-app, SMS, etc.) produce
 * Notification records and accept NotificationPayload inputs.
 */

/**
 * Supported notification channels. Extend this union to add new channels.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in-app' | 'sms';

/**
 * Categories of notifications for routing and preference management.
 */
export type NotificationType =
  | 'order-confirmation'
  | 'order-status-update'
  | 'user-welcome'
  | 'user-profile-update'
  | 'system-alert';

/**
 * Priority levels for notification delivery ordering.
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'critical';

/**
 * The payload passed to notification adapters for delivery.
 */
export interface NotificationPayload {
  /** Target recipient identifier (email address, user ID, webhook URL, etc.) */
  recipient: string;
  /** Notification subject / title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Which channel to deliver through */
  channel: NotificationChannel;
  /** Categorization for routing and preferences */
  type: NotificationType;
  /** Delivery priority */
  priority: NotificationPriority;
  /** Optional structured metadata for adapter-specific needs */
  metadata?: Record<string, unknown>;
}

/**
 * Result of a notification delivery attempt.
 */
export type NotificationStatus = 'sent' | 'failed' | 'pending';

/**
 * A persisted notification record.
 */
export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  type: NotificationType;
  priority: NotificationPriority;
  status: NotificationStatus;
  metadata?: Record<string, unknown>;
  sentAt: Date;
}

/**
 * NotificationAdapter interface — the contract all notification channel
 * implementations must fulfill.
 *
 * Architecture constraint: Every notification channel (email, webhook, SMS,
 * in-app) must be implemented as a class that implements this interface and
 * registered with the NotificationService. The NotificationService routes
 * payloads to the appropriate adapter based on the channel field.
 *
 * Adapters are responsible for:
 * - Transforming the generic NotificationPayload into channel-specific format
 * - Performing the actual delivery (or stubbing it)
 * - Returning a success/failure result
 *
 * Adapters must NOT:
 * - Subscribe to the EventBus directly (the NotificationService handles that)
 * - Maintain their own notification log (the NotificationService tracks records)
 * - Throw exceptions for delivery failures (return { success: false } instead)
 */

import type { NotificationChannel, NotificationPayload } from '../models/notification.js';

/**
 * Result of an adapter's send attempt.
 */
export interface AdapterSendResult {
  success: boolean;
  /** Optional error message on failure */
  error?: string;
  /** Optional channel-specific response data (e.g., message ID from provider) */
  providerResponse?: Record<string, unknown>;
}

/**
 * The interface all notification adapters must implement.
 */
export interface NotificationAdapter {
  /** Which channel this adapter handles */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * Must not throw — return { success: false, error } on failure.
   */
  send(payload: NotificationPayload): Promise<AdapterSendResult>;
}

/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel. Currently a stub
 * that records sent emails in memory. Replace the send() internals with a
 * real email provider (SES, SendGrid, SMTP, etc.) for production use.
 */

import type { NotificationAdapter, AdapterSendResult } from './notification.adapter.js';
import type { NotificationPayload } from '../models/notification.js';
import type { NotificationChannel } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * A recorded email for inspection in tests and debugging.
 */
export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  async send(payload: NotificationPayload): Promise<AdapterSendResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    // Stub: record in memory instead of calling an email provider
    const email: SentEmail = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);

    return { success: true };
  }

  /**
   * Get all emails sent through this adapter. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear recorded emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — the central hub that bridges domain events to
 * notification delivery through pluggable adapters.
 *
 * Architecture:
 * - Subscribes to domain events via EventBus (the ONLY way notifications are triggered)
 * - Routes notifications to registered NotificationAdapter implementations
 * - Maintains a log of all notification records
 *
 * Constraints:
 * - All notifications flow through EventBus.emit() — no direct calls
 * - Adapters must implement NotificationAdapter and be registered via registerAdapter()
 * - This service is the sole bridge between domain events and notification delivery
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events
 * - NotificationAdapter implementations for channel-specific delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a specific channel.
   * Only one adapter per channel is supported — later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to all domain events that should trigger notifications.
   * This is the ONLY place where event-to-notification mapping is defined.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.send({
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      channel: 'email',
      type: 'order-confirmation',
      priority: 'normal',
    });
  }

  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.send({
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      channel: 'email',
      type: 'order-status-update',
      priority: 'normal',
    });
  }

  /**
   * Send a notification through the appropriate adapter and record it.
   * This is the single delivery path — all notifications go through here.
   */
  async send(payload: NotificationPayload): Promise<Notification> {
    const adapter = this.adapters.get(payload.channel);

    const notification: Notification = {
      id: generateNotificationId(),
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      channel: payload.channel,
      type: payload.type,
      priority: payload.priority,
      status: 'pending',
      metadata: payload.metadata,
      sentAt: new Date(),
    };

    if (!adapter) {
      this.logger.warn(`No adapter registered for channel: ${payload.channel}`);
      notification.status = 'failed';
      this.notifications.push(notification);
      return notification;
    }

    const result = await adapter.send(payload);
    notification.status = result.success ? 'sent' : 'failed';
    if (result.providerResponse) {
      notification.metadata = { ...notification.metadata, providerResponse: result.providerResponse };
    }

    this.notifications.push(notification);
    this.logger.info(`Notification ${notification.id} ${notification.status} via ${payload.channel} to ${payload.recipient}`);

    return notification;
  }

  /**
   * Get all notification records.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notification records (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

